#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, k;
        scanf("%d %d", &n, &k);
        if (k > n * (n + 1) / 4) {
            printf("impossible\n");
        } else {
            int i = 0;
            while (i < n && k > (i + 1) / 2) {
                printf("(");
                printf(")");
                k -= (i + 1) / 2;
                i += 2;
            }
            while (i < n) {
                printf("(");
                i++;
            }
            while (i < n) {
                printf(")");
                i++;
            }
            printf("\n");
        }
    }
    return 0;
}

